glsl3.vert:
precision highp float;
uniform CCGlobal {
  mat4 cc_matView;
  mat4 cc_matViewInv;
  mat4 cc_matProj;
  mat4 cc_matProjInv;
  mat4 cc_matViewProj;
  mat4 cc_matViewProjInv;
  vec4 cc_cameraPos;
  vec4 cc_time;
  mediump vec4 cc_screenSize;
  mediump vec4 cc_screenScale;
};
uniform CCLocal {
  mat4 cc_matWorld;
  mat4 cc_matWorldIT;
};
in vec3 a_position;
in vec2 a_uv0;
out vec2 v_uv0;
void main () {
    v_uv0 = a_uv0;
    gl_Position = cc_matProj * cc_matView * cc_matWorld * vec4(a_position, 1.0);
}

glsl3.frag:
precision highp float;
#if USE_ALPHA_TEST
  uniform ALPHA_TEST {
    float alphaThreshold;
  };
#endif
in vec2 v_uv0;
uniform sampler2D texture;
uniform fsUniforms {
    float time;
    float speed;
    float amplitude;
    float rangeMin;
    float rangeMax;
    float direction;
};
void main () {
    vec2 uv = v_uv0;
    float range = rangeMax - rangeMin;
    float sinWave = sin(time * speed * 0.5);
    float breathe = mix(-abs(sinWave) * 2.0, abs(sinWave) * 2.0, step(0.5, direction));
    float edgeOffset = breathe * amplitude;
    if (uv.y > rangeMin && uv.y < rangeMax) {
        float t = (uv.y - rangeMin) / range;
        float offset = edgeOffset * (1.0 - t);
        uv.y += offset;
    }
    else if (uv.y <= rangeMin) {
        uv.y += edgeOffset;
    }
    if (uv.y < 0.0 || uv.y > 1.0 || uv.x < 0.0 || uv.x > 1.0) {
        gl_FragColor = vec4(0.0, 0.0, 0.0, 0.0);
    } else {
        gl_FragColor = texture2D(texture, uv);
    }
}

